extern char *str_dup(const char *s);
if (!s) return str_dup("");
size_t n = strlen(s);
char *out = (char *)malloc(n * 2 + 1);
if (!out) return NULL;
size_t oi = 0;
for (size_t i = 0; i < n; i++) {
    char c = s[i];
    if (c == '"' || c == '\\' || c == '\n' || c == '\r' || c == '\t') {
        out[oi++] = '\\';
        if (c == '\n') out[oi++] = 'n';
        else if (c == '\r') out[oi++] = 'r';
        else if (c == '\t') out[oi++] = 't';
        else out[oi++] = c;
    } else {
        out[oi++] = c;
    }
}
out[oi] = '\0';
return out;
